from qiskit import QuantumCircuit, QuantumRegister, ClassicalRegister

def fresh():
    qr = QuantumRegister(2, 'q'); cr = ClassicalRegister(2, 'c')
    qc = QuantumCircuit(qr, cr); qc.h(0); qc.measure(0, 0)
    return qc, cr

evidence = {}
proven = []

def check(key, fn):
    try:
        qc = fn()
        has_if = "if_else" in qc.count_ops()
        evidence[key] = f"built successfully; ops={dict(qc.count_ops())}; has if_else={has_if}"
        if has_if:
            proven.append(key)
    except Exception as e:
        evidence[key] = f"raised {type(e).__name__}: {str(e)[:110]}"

def A():
    qc, cr = fresh(); qc.x(1).c_if(cr[0], 1); return qc
def B():
    qc, cr = fresh()
    with qc.if_test(cr[0], 1):
        qc.x(1)
    return qc
def C():
    qc, cr = fresh()
    with qc.if_test((cr[0], 1)):
        qc.x(1)
    return qc
def D():
    qc, cr = fresh(); qc.if_test((cr[0], 1), qc.x, [1]); return qc

check("A", A); check("B", B); check("C", C); check("D", D)
emit_verdict({"answer": proven, "evidence": evidence, "observed": {"proven": proven}})
